INSERT INTO gencine_hadiths (sort_order, title, ar, ku, source, active) VALUES
  (1546, 'كارى ل بەر خەلكى ب ساناهى بكەن', 'عن أَنَسِ بْنِ مَالِكٍ رضي الله عنه عنْ رَسُولِ اللهﷺ قَالَ: «يَسِّرُوا وَلاَ تُعَسِّرُوا، وَبَشِّروا وَلاَ تُنَفِّرُوا».', 'ئه‌نه‌سێ كوڕێ مالكى -خودێ ژێ رازى بت- دبێژت: پێغه‌مبه‌رى -سلاڤ لێ بن- گۆت: ل به‌ر خه‌لكى ب ساناهى بێخن و ب زه‌حمه‌ت نه‌كه‌ن، و مزگینییێ بگه‌هینن و خه‌لكى ژ خۆ نه‌ڕه‌ڤینن.', NULL, true),
  (1556, 'كیژ مرۆڤ چێترە؟', 'عَنْ أَبِي سَعِيدٍ رضي الله عنه قَالَ: قَالَ رَجُلٌ: أَيُّ النَّاسِ أَفْضَلُ يَا رَسُولَ الله؟ قَالَ: «مُؤْمِنٌ يُجَاهِدُ بِنَفْسِهِ وَمَالِهِ فِي سَبِيلِ الله» قَالَ: ثُمَّ مَنْ؟ قَالَ: «ثُمَّ رَجُلٌ مُعْتَزِلٌ فِي شِعْبٍ مِنَ الشِّعَابِ يَعْبُدُ رَبَّهُ، وَيَدَعُ النَّاسَ مِنْ شَرِّهِ».', 'ئه‌بوو سه‌عید -خودێ ژێ رازى بت- دبێژت: زه‌لامه‌كى گۆت: كیژ مرۆڤ چێتره‌ ئه‌ى پێغه‌مبه‌رێ خودێ؟ وى گۆت: خودان باوه‌ره‌كێ جیهادێ ب نه‌فسا خۆ و مالێ خۆ د ڕێكا خودێ دا دكه‌ت. گۆت: پاشى كى؟ وى گۆت: پاشى زه‌لامـه‌كـێ خــۆ د گـه‌لییان دا ڤه‌ده‌ركه‌ت، په‌ڕستنا خودایێ خۆ بكه‌ت، و به‌لا خۆ ژ خه‌لكى ڤه‌كه‌ت.', NULL, true),
  (1566, 'سێ كەسێن خودێ ل قیامەتێ د گەل نائاخڤت', 'عَنْ أَبِي هُرَيْرَةَ رضي الله عنه قَالَ: قَالَ رَسُولُ اللهﷺ : «ثَلاَثٌ لاَ يُكَلِّمُهُمُ الله يَوْمَ الْقِيَامَةِ، وَلاَ يَنْظُرُ إِلَيْهِمْ، وَلاَ يُزَكِّيهِمْ وَلَهُمْ عَذَابٌ أَلِيمٌ: رَجُلٌ عَلَى فَضْلِ مَاءٍ بِالْفَلاَةِ يَمْنَعُهُ مِنَ ابْنِ السَّبِيلِ، وَرَجُلٌ بَايَعَ رَجُلاً بِسِلْعَةٍ بَعْدَ الْعَصْرِ فَحَلَفَ لَهُ بِالله لأَخَذَهَا بِكَذَا وَكَذَا فَصَدَّقَهُ وَهُوَ عَلَى غَيْرِ ذَلِكَ، وَرَجُلٌ بَايَعَ إِمَامًا لاَ يُبَايِعُهُ إِلاَّ لِدُنْيَا فَإِنْ أَعْطَاهُ مِنْهَا وَفَى، وَإِنْ لَمْ يُعْطِهِ مِنْهَا لَمْ يَفِ».', 'ئه‌بوو هوره‌یره‌ -خودێ ژێ رازى بت- دبێژت: پێغه‌مبه‌رى -سلاڤ لێ بن- گۆت: سێ كه‌س هه‌نه‌ خودێ ڕۆژا قیامه‌تێ د گه‌ل وان نائاخڤت، و به‌رێ خۆ ناده‌تێ، و عه‌زابه‌كا ب ئێش بۆ وان هه‌یه‌: زه‌لامه‌كێ ئاڤه‌كا زێده‌ ل به‌ڕییێ د گه‌ل دا بت، و ئه‌و وێ نه‌ده‌ته‌ ڕێڤنگى، و زه‌لامه‌كێ پشتى ئێڤارى په‌رتاله‌ك فرۆتییه‌ زه‌لامه‌كى و سویند ب خودێ خوارى كو وى ئه‌و ب هندێ و هندێ وه‌رگرتییه‌ ڤێجا باوه‌رییا وى پێ بێت و ئه‌و ب خۆ وه‌سا نه‌بت، و زه‌لامه‌كێ ب دنیایێ به‌یعه‌ دایه‌ ئیمامه‌كى، ڤێجا ئه‌گه‌ر ئه‌و تشته‌كى ژ دنیایێ بده‌تێ ئه‌و د گه‌ل وى یێ ب وه‌فا بت، و ئه‌گه‌ر چو نه‌دایێ یێ ب وه‌فا نه‌بت.', NULL, true),
  (1576, 'هندەك باوەرییێن نەدورست', 'عن أَبي هُرَيْرَةَ رضي الله عنه قَالَ: قال رَسُول اللهﷺ : «لاَ عَدْوَى وَلاَ طِيَرَةَ وَلاَ هَامَةَ وَلاَ صَفَرَ».', 'ئه‌بوو هوره‌یره‌ -خودێ ژێ رازى بت- دبێژت: پێغه‌مبه‌رى -سلاڤ لێ بن- گۆت: چو ڤه‌گرتن، و بێ ئیفله‌حى، ب طه‌یران و ئێشا زكى نینه‌.', NULL, true),
  (1586, 'مرۆڤ هەمى بەرپڕسن', 'عن عَبْدِ الله بْنِ عُمَرَ رضي الله عنه يَقُولُ: سَمِعْتُ رَسُولَ اللهﷺ يَقُولُ: «كُلُّكُمْ رَاعٍ وَكُلُّكُمْ مَسْؤُولٌ عَنْ رَعِيَّتِهِ، الإِمَامُ رَاعٍ وَمَسْؤُولٌ عَنْ رَعِيَّتِهِ، وَالرَّجُلُ رَاعٍ فِي أَهْلِهِ وَهْوَ مَسْؤُولٌ عَنْ رَعِيَّتِهِ، وَالْمَرْأَةُ رَاعِيَةٌ فِي بَيْتِ زَوْجِهَا وَمَسْؤُولَةٌ عَنْ رَعِيَّتِهَا، وَالخَادِمُ رَاعٍ فِي مَالِ سَيِّدِهِ وَمَسْؤُولٌ عَنْ رَعِيَّتِهِ، وَالرَّجُلُ رَاعٍ فِي مَالِ أَبِيهِ وَمَسْؤُولٌ عَنْ رَعِيَّتِهِ، وَكُلُّكُمْ رَاعٍ وَمَسْؤُولٌ عَنْ رَعِيَّتِهِ».', 'عه‌بدللاهێ كوڕێ عومه‌رى -خودێ ژ هه‌ردویان رازى بت- دبێژت: پێغه‌مبه‌رى -سلاڤ لێ بن- گۆت: هوین هه‌مى شڤانن و هوین هه‌مى ژ شڤانییا خۆ به‌رپڕسن، و زه‌لام د مالا خۆ دا شڤانه‌ و ئــه‌و ژ شـڤـانییا خۆ به‌رپڕسه‌، و ژن د مالا زه‌لامێ خۆ دا شڤانه‌ و ئه‌و ژ شڤانییا خۆ به‌رپڕسه‌، و خزمه‌تكار د مالێ باخویێ خۆ دا شڤانه‌ و ئه‌و ژ شڤانییا خۆ به‌رپڕسه‌، و زه‌لام د مالێ بابێ خۆ دا شڤانه‌ و ئه‌و ژ شڤانییا خۆ به‌رپڕسه‌، و هوین هه‌مى شڤانن و ژ شڤانییا خۆ به‌رپڕسن.', NULL, true),
  (1596, 'گرنگییا ژنئینان و شویكرنێ', 'عَنْ عَبْدِ الله بن مسعود رضي الله عنه قَالَ: قَالَ رَسُولُ اللهﷺ : «يَا مَعْشَرَ الشَّبَابِ، مَنِ اسْتَطَاعَ مِنْكُمُ الْبَاءَةَ فَلْيَتَزَوَّجْ، فَإِنَّهُ أَغَضُّ لِلْبَصَرِ، وَأَحْصَنُ لِلْفَرْجِ، وَمَنْ لَمْ يَسْتَطِعْ فَعَلَيْهِ بِالصَّوْمِ، فَإِنَّهُ لَهُ وِجَاءٌ».', 'عـه‌بـدللاهــێ كوڕێ مه‌سعوودى -خودێ ژێ رازى بت- دبێژت: پێغه‌مبه‌رى -سلاڤ لێ بن- گۆت: گه‌لى جحێلان هه‌چییێ ژ هه‌وه‌ شیا ژنێ بینت بلا بینت، ئه‌و پتر چاڤى دگرت و نامویسێ دپارێزت، و هه‌چییێ نه‌شێت بلا ڕۆژییێ بگرت، ئه‌و بۆ وى په‌رژانه‌.', NULL, true),
  (1606, 'ئەگەرێن مارەكرنا ژنێ', 'عَنْ أَبِي هُرَيْرَةَ رضي الله عنه عَنِ النَّبِيِّﷺ قَالَ: «تُنْكَحُ المَرْأَةُ لِأَرْبَعٍ: لِمَالِهَا، وَلِحَسَبِهَا، وَلِجَمَالِهَا، وَلِدِينِهَا، فَاظْفَرْ بِذَاتِ الدِّينِ تَرِبَتْ يَدَاكَ».', 'ئه‌بوو هوره‌یره‌ -خودێ ژێ رازى بت- دبێژت: پێغه‌مبه‌رى -سلاڤ لێ بن- گۆت: ژن ژ به‌ر چار تشتان دئێته‌ ماره‌كرن: ژ به‌ر مالێ وێ، و مالباتا وێ، و جوانییا وێ، و دینێ وێ، ڤێجا تو یا خودان دین ب ده‌ست خۆ بێخه‌‌.', NULL, true),
  (1616, 'وه ئێمانەت ژن', 'عَنْ أَبِي هُرَيْرَةَ رضي الله عنه عَنِ النَّبِيِّﷺ قَالَ: «مَنْ كَانَ يُؤْمِنُ بِالله وَالْيَوْمِ الآخِرِ فَلا يُؤْذِى جَارَهُ، وَاسْتَوْصُوا بِالنِّسَاءِ خَيْرًا، فَإِنَّهُنَّ خُلِقْنَ مِنْ ضِلَعٍ، وَإِنَّ أَعْوَجَ شَىْءٍ فِى الضِّلَعِ أَعْلاهُ، فَإِنْ ذَهَبْتَ تُقِيمُهُ كَسَرْتَهُ، وَإِنْ تَرَكْتَهُ لَمْ يَزَلْ أَعْوَجَ، فَاسْتَوْصُوا بِالنِّسَاءِ خَيْرًا».', 'ئه‌بوو هوره‌یره‌ -خودێ ژێ رازى بت- دبێژت: پێغه‌مبه‌رى -سلاڤ لێ بن- گۆت: هه‌چییێ باوه‌رى ب خودێ و ڕۆژا دووماهییێ هه‌بت بلا نه‌خۆشییێ نه‌گه‌هینته‌ جیرانێ خۆ، و وه‌ ئـێـمـانــه‌ت ژن د گــه‌ل دبــاش بــن، چـونكى ئه‌و یێ ژ په‌ڕاسییێ هاتینه‌ ئافراندن، و جهێ ژ هه‌مییێ خوارتر د په‌ڕاسییێ دا سه‌رێ وییه‌، و ئه‌گه‌ر تو بچى ڕاست كه‌ى دێ شكێنى و ئه‌گه‌ر تو بهێلى دێ مینت خوار، ڤێجا د گه‌ل ژنان دباش بن.', NULL, true),
  (1626, 'گونەها وێ ژنا د بەرسڤا مێرێ خۆ نەچت', 'عَنْ أَبِي هُرَيْرَةَ رضي الله عنه قَالَ: قَالَ رَسُولُ اللهﷺ : «إِذَا دَعَا الرَّجُلُ امْرَأَتَهُ إِلَى فِرَاشِهِ، فَلَمْ تَأْتِهِ، فَبَاتَ غَضْبَانَ عَلَيْهَا، لَعَنَتْهَا المَلَائِكَةُ حَتَّى تُصْبِحَ».', 'ئه‌بوو هوره‌یره‌ -خودێ ژێ رازى بت- دبێژت: پێغه‌مبه‌رى -سلاڤ لێ بن- گۆت: ئه‌گه‌ر زه‌لامى ژن بۆ نڤینا خۆ داخوازكر و ئه‌و د به‌رسڤا وى نه‌چوو، و ئه‌و بنڤت و یێ ژێ عێجز، حه‌تا سپێدێ ملیاكه‌ت له‌عنه‌تان ل وێ دكه‌ن.', NULL, true),
  (1636, 'كارێ شەیطانى د گەل مرۆڤى', 'عَنْ أم المؤمنین صَفِيَّةَ بِنْتِ حُيَيٍّ -رضي الله عنها- قَالَتْ: كَانَ النَّبِيُّﷺ مُعْتَكِفًا، فَأَتَيْتُهُ أَزُورُهُ لَيْلًا، فَحَدَّثْتُهُ، ثُمَّ قُمْتُ لِأَنْقَلِبَ، فَقَامَ مَعِيَ لِيَقْلِبَنِي، فَمَرَّ رَجُلَانِ مِنَ الْأَنْصَارِ، فَلَمَّا رَأَيَا النَّبِيَّﷺ أَسْرَعَا، فَقَالَ النَّبِيُّﷺ : «عَلَى رِسْلِكُمَا، إِنَّهَا صَفِيَّةُ بِنْتُ حُيَيٍّ» فَقَالَا: سُبْحَانَ الله يَا رَسُولَ الله، قَالَ: «إِنَّ الشَّيْطَانَ يَجْرِي مِنَ الْإِنْسَانِ مَجْرَى الدَّمِ، وَإِنِّي خَشِيتُ أَنْ يَقْذِفَ فِي قُلُوبِكُمَا شَرًّا أَوْ قَالَ شَيْئًا».', 'ده‌یكا خودان باوه‌ران صه‌فییایا كچا حویه‌یى -خودێ ژێ رازى بت- دبێژت: پێغه‌مبه‌ر -سلاڤ لێ بن- د ئعتكافێ دا بوو، شه‌ڤه‌كێ ئه‌ز هاتم سه‌را بده‌م، ئه‌ز د گه‌ل ئاخفتم، پاشى ئه‌ز ڕابووم دا بزڤڕمه‌ڤه‌، ئه‌و ژى ڕابوو دا من بده‌ته‌ ڕێ، دو زه‌لامێن ئه‌نصارى بۆرین، و گاڤا وان پێغه‌مبه‌ر -سلاڤ لێ بن- دیتى وان پییێن خۆ سڤك كرن، پێغه‌مبه‌رى -سلاڤ لێ بن- گۆت: له‌زێ نه‌كه‌ن، ئه‌ڤه‌ صه‌فییایا كچا حویه‌یه‌. وان گۆت: (سبحان الله) ئه‌ى پێغه‌مبه‌رێ خودێ! وى گۆت: هندى شه‌یطانه‌ د جهێ خوینێ ڕا ژ مرۆڤى دگه‌ڕیێت، و ئه‌ز ترسیام ئه‌و خرابییه‌كێ یان گۆت تشته‌كى بهاڤێته‌ دلێن هه‌وه‌.', NULL, true),
  (1646, 'وەفادارییا پێغەمبەرى د گەل خەدیجایێ', 'عَنْ عَائِشَةَ -رَضِيَ الله عَنْهَا- قَالَتْ: مَا غِرْتُ عَلَى أَحَدٍ مِنْ نِسَاءِ النَّبِيِّﷺ مَا غِرْتُ عَلَى خَدِيجَةَ، وَمَا رَأَيْتُهَا، وَلَكِنْ كَانَ النَّبِيُّﷺ يُكْثِرُ ذِكْرَهَا، وَرُبَّمَا ذَبَحَ الشَّاةَ ثُمَّ يُقَطِّعُهَا أَعْضَاءً ثُمَّ يَبْعَثُهَا فِي صَدَائِقِ خَدِيجَةَ، فَرُبَّمَا قُلْتُ لَهُ: كَأَنَّهُ لَمْ يَكُنْ فِي الدُّنْيَا امْرَأَةٌ إِلاَّ خَدِيجَةُ! فَيَقُولُ: «إِنَّهَا كَانَتْ وَكَانَتْ، وَكَانَ لِي مِنْهَا وَلَدٌ».', 'ده‌یكا خودان باوه‌ران عائیشا -خودێ ژێ رازى بت- دبێژت: غیره‌ت بۆ من ل سه‌ر ئێك ژ ژنكێن پێغه‌مبه‌رى -سلاڤ لێ بن- چێ نه‌بوویه‌ وه‌كى كو غیره‌ت بۆ من ل سه‌ر خه‌دیجایێ چێبووى، و من ئه‌و نه‌دیتبوو، به‌لێ پێغه‌مبه‌رى -سلاڤ لێ بن- گه‌له‌ك به‌حسێ وێ دكر، و ده‌مێ وى په‌زه‌ك ڤه‌كوشتبا، وى ئه‌و پارچه‌ پارچه‌ دكر، و ل سه‌ر هه‌ڤالێن خه‌دیجایێ لێكڤه‌دكر، و جاره‌كێ من گۆتێ: هه‌ر وه‌كى چو ژن ژ بلى خه‌دیجایێ د دنیایێ دا نه‌بوون؟! وى گۆت: ئه‌و یا هۆسا بوو و هۆسا بوو.. و من عه‌یال ژ وێ هه‌بوو.', NULL, true),
  (1656, 'زڤڕین ژ وەغەرێ ل ئێڤارییان', 'عَنْ جَابِرِ بْنِ عَبْدِ الله رضي الله عنه قَالَ: كُنَّا مَعَ رَسُولِ اللهﷺ فِي غَزَاةٍ، فَلَمَّا قَدِمْنَا المَدِينَةَ، ذَهَبْنَا لِنَدْخُلَ، فَقَالَ: «أَمْهِلُوا حَتَّى نَدْخُلَ لَيْلًا -أَيْ عِشَاءً- كَيْ تَمْتَشِطَ الشَّعِثَةُ، وَتَسْتَحِدَّ المُغِيبَةُ».', 'جابرێ كوڕێ عه‌بدللاهى -خودێ ژێ رازى بت- دبێژت: ئه‌م د گه‌ل پێغه‌مبه‌رى -سلاڤ لێ بن- د غه‌زایه‌كێ دا بووین، و ده‌مێ ئه‌م هاتینه‌ مه‌دینێ، ئه‌م چووین دا قه‌ستا مالێن خۆ بكه‌ین، ئینا پێغه‌مبه‌رى -سلاڤ لێ بن- گۆت: له‌زێ نه‌كه‌ن حه‌تا ل مه‌ دبته‌ ئێڤار؛ دا ژن سه‌رێن خۆ شه‌ بكه‌ن، و خۆ پاقژ بكه‌ن.', NULL, true),
  (1666, 'نیهارا ژنێ ل سەر مرى', 'عَنْ زَيْنَبَ بِنْتِ أَبِي سَلَمَةَ -رضي الله عنها- قَالَتْ: دَخَلْتُ عَلَى أُمِّ حَبِيبَةَ زَوْجِ النَّبِيِّﷺ حِينَ تُوُفِّيَ أَبُوهَا أَبو سُفْيَانَ، فَدَعَتْ أُمُّ حَبِيبَةَ بِطِيبٍ فِيهِ صُفْرَةٌ خَلُوقٌ أَوْ غَيْرُهُ فَدَهَنَتْ مِنْهُ جَارِيَةً، ثُمَّ مَسَّتْ بِعَارِضَيْهَا، ثُمَّ قَالَتْ: وَالله مَا لِي بِالطِّيبِ مِنْ حَاجَةٍ، غَيْرَ أَنِّي سَمِعْتُ رَسُولَ اللهﷺ يَقُولُ عَلَى الْمِنْبَرِ: «لَا يَحِلُّ لِامْرَأَةٍ تُؤْمِنُ بِالله وَالْيَوْمِ الْآخِرِ تُحِدُّ عَلَى مَيِّتٍ فَوْقَ ثَلَاثٍ، إِلَّا عَلَى زَوْجٍ أَرْبَعَةَ أَشْهُرٍ وَعَشْرًا».', 'زه‌ینه‌با كچا ئه‌بوو سه‌له‌مه‌یى -خودێ ژێ رازى بت- دبێژت: ئه‌ز چوومه‌ نك كابانییا پێغه‌مبه‌رى -سلاڤ لێ بن- ئه‌م حه‌بیبه‌یێ ده‌مێ بابێ وێ ئه‌بوو سوفیان مرى، وێ هنده‌ك بێنا خۆش داخوازكر، و هنده‌ك ژێ ل كچه‌كێ كر پاشى ده‌ستێن خۆ د جێنیكێن خۆ دان و گۆت: ب خودێ من چو هه‌وجه‌یى ب بێنا خۆش نینه‌، به‌لێ من گوهـ ل پێغه‌مبه‌رى -سلاڤ لێ بن- بوویه‌ وى ل سه‌ر مینه‌به‌رێ دگۆت: حه‌لال نینه‌ بۆ ژنه‌كا باوه‌رى ب خودێ و ڕۆژا دووماهییێ هه‌ى كو ئه‌و پتر ژ سێ ڕۆژان نیهارێ ل سه‌ر مرییه‌كى بكه‌ت، ل سه‌ر زه‌لامێ وێ تێ نه‌بت، ئه‌و چار هه‌یڤ و ده‌هـ ڕۆژان بۆ وى دێ وێ چه‌ندێ كه‌ت.', NULL, true),
  (1676, 'خویشك و براینییا شیرى', 'عَـنِ ابْنِ عَبَّاسٍ رضي الله عنه أَنَّ النَّبِيَّﷺ أُرِيدَ عَلَى ابْنَةِ حَمْزَةَ، فَـقَـالَ: «إِنَّهَا لَا تَحِلُّ لِي، إِنَّهَا ابْنَةُ أَخِي مِنَ الرَّضَاعَةِ، وَيَحْرُمُ مِنَ الرَّضَاعَةِ مَا يَحْرُمُ مِنَ الرَّحِمِ».', 'عه‌بدللاهێ كوڕێ عه‌بباسى -خودێ ژ هه‌ردویان رازى بت- دبێژت: بۆ پێغه‌مبه‌رى -سلاڤ لێ بن- هاته‌ حه‌زكرن كو ئه‌و كچا حه‌مزه‌یى ماره‌ بكه‌ت، وى گۆت: ئه‌و بۆ من یا حه‌لال نینه‌، ئه‌و كچا برایێ من یێ شیرییه‌، و ئه‌و ب شیرى حه‌رام دبت یا ب نه‌سه‌بێ حه‌رام دبت.', NULL, true),
  (1686, 'خۆشتڤیترین كار ل نك خودێ', 'عن عَبْدِ الله بن مسعود رضي الله عنه قَالَ: سَأَلْتُ رَسُولَ اللهﷺ : أَيُّ الْأَعْمَالِ أَحَبُّ إِلَى الله؟ قَالَ: «الصَّلَاةُ عَلَى وَقْتِهَا» قُلْتُ: ثُمَّ أَيٌّ؟ قَالَ: «ثُمَّ بِرُّ الْوَالِدَيْنِ» قُلْتُ: ثُمَّ أَيٌّ؟ قَالَ: «ثُمَّ الْجِهَادُ فِي سَبِيلِ الله».', 'عـه‌بـدللاهــێ كــوڕێ مه‌سعوودى -خودێ ژێ رازى بت- دبێژت: من پسیار ژ پێغه‌مبه‌رى -سلاڤ لێ بن- كر كیژ كار خۆشتڤیترین كارن ل نك خودێ؟ وى گۆت: نڤێژ ل ده‌مێ وێ، من گۆت: پاشى چ؟ وى گۆت: پاشى قه‌نجییا د گه‌ل ده‌یبابان. من گۆتێ: پاشى چ؟ وى گۆت: پاشى جیهادا د ڕێكا خودێ دا.', NULL, true),
  (1696, 'تشتێ خودێ ل سەر هەوه حەرامكرى و تشتێ وى بۆ هەوه نەڤیاى', 'عَنِ المُغِيرَةِ بْنِ شُعْبَةَ رضي الله عنه عَنْ رَسُولِ اللهﷺ قَالَ: «إِنَّ اللهَ عَزَّ وَجَلَّ حَرَّمَ عَلَيْكُمْ: عُقُوقَ الْأُمَّهَاتِ، وَوَأْدَ الْبَنَاتِ، وَمَنْعًا وَهَاتِ، وَكَرِهَ لَكُمْ ثَلَاثًا: قِيلَ وَقَالَ، وَكَثْرَةَ السُّؤَالِ، وَإِضَاعَةَ المَالِ».', 'موغیره‌یێ كوڕێ شـوعــبـه‌یـى -خودێ ژێ رازى بت- دبــێــژت: پـێـغه‌مبه‌رى -سلاڤ لێ بن- گۆت: هندى خودایێ پاك و بلنده‌ هێلانا دلێ ده‌یكان، و ڤه‌شارتنا كچان ب ساخى و گرتنا مالى و به‌س كۆمكرن ل سه‌ر هه‌وه‌ حه‌رامكرییه‌، و وى سێ تشت بۆ هه‌وه‌ نه‌ڤیاینه‌: گۆتۆیى گۆت، و گه‌له‌ك خواستن، و زه‌عێكرنا مالى.', NULL, true),
  (1706, 'كی هێژاتره بۆ هەڤالینییا من؟', 'عَنْ أَبِي هُرَيْرَةَ رضي الله عنه قَالَ: جَاءَ رَجُلٌ إِلَى رَسُولِ اللهﷺ، فَقَالَ: مَنْ أَحَقُّ النَّاسِ بِحُسْنِ صَحَابَتِي؟ قَالَ: «أُمُّكَ» قَالَ: ثُمَّ مَنْ؟ قَالَ: «ثُمَّ أُمُّكَ» قَالَ: ثُمَّ مَنْ؟ قَالَ: «ثُمَّ أُمُّكَ» قَالَ: ثُمَّ مَنْ؟ قَالَ: «ثُمَّ أَبُوكَ».', 'ئه‌بوو هوره‌یره‌ -خودێ ژێ رازى بت- دبێژت: زه‌لامه‌ك هاته‌ نك پێغه‌مبه‌رى -سلاڤ لێ بن- و گۆتێ: كیژ ژ مرۆڤ هێژاتره‌ بۆ باشییا هه‌ڤالینییا من؟ وى گۆت: ده‌یكا ته‌، گۆتێ: پاشى كى؟ وى گۆت: پاشى ده‌یكا ته‌، وى گۆت: پاشى كى؟ وى گۆت: پاشى ده‌یكا ته‌، گۆتێ: پاشى كى؟ وى گۆت: پاشى بابێ ته‌.', NULL, true),
  (1716, 'دادى د ناڤبەرا عەیالى دا', 'عَنِ النُّعْمَانِ بْنِ بَشِيرٍ رضي الله عنه قَالَ: تَصَدَّقَ عَلَيَّ أَبِي بِبَعْضِ مَالِهِ، فَقَالَتْ أُمِّي عَمْرَةُ بِنْتُ رَوَاحَةَ: لَا أَرْضَى حَتَّى تُشْهِدَ رَسُولَ اللهﷺ، فَانْطَلَقَ أَبِي إِلَى النَّبِيِّﷺ لِيُشْهِدَهُ عَلَى صَدَقَتِي، فَقَالَ لَهُ رَسُـولُ الله رضي الله عنه : «أَفَعَلْتَ هَذَا بِوَلَدِكَ كُلِّهِمْ؟» قَالَ: لَا، قَالَ: «اتَّقُوا اللهَ، وَاعْدِلُوا فِي أَوْلَادِكُمْ»، فَرَجَعَ أَبِي، فَرَدَّ تِلْكَ الصَّدَقَةَ.', 'نوعمانێ كوڕێ به‌شیرى -خودێ ژێ رازى بت- دبێژت: بابێ من هنده‌ك مالێ خۆ ب خێر دا من، ئینا ده‌یكا من عه‌مره‌یا كچا ره‌واحه‌یى گۆت: ئه‌ز رازى نابم حه‌تا تو پێغه‌مبه‌رى -سلاڤ لێ بن- بكه‌یه‌ شاهد، هنگى بابێ من چوو نك پێغه‌مبه‌رى -سلاڤ لێ بن- دا وى بكه‌ته‌ شاهد ل سه‌ر وێ خێرا وى دایه‌ من، پێغه‌مبه‌رى -سلاڤ لێ بن- گۆتێ: ته‌ ئه‌ڤ چه‌نده‌ د گه‌ل هه‌مى عه‌یالێ خۆ كرییه‌؟ وى گۆت: نه‌خێر، پێغه‌مبه‌رى -سلاڤ لێ بن- گۆتێ: ژ خودێ بترسن و دادییێ د ناڤبه‌را عه‌یالێ خۆ دا بكه‌ن. ڤێجا بابێ من زڤڕى و ئه‌و خێرا دایه‌ من زڤڕاند.', NULL, true),
  (1726, 'یێ ب رەحم نەبت رەحم پێ نائێتەبرن', 'عَنْ أَبِي هُرَيْرَةَ رضي الله عنه أَنَّ الْأَقْرَعَ بْنَ حَابِسٍ، أَبْصَرَ النَّبِيَّﷺ يُقَبِّلُ الحَسَنَ فَقَالَ: إِنَّ لِي عَشَرَةً مِنَ الْوَلَدِ مَا قَبَّلْتُ وَاحِدًا مِنْهُمْ، فَقَالَ رَسُولُ اللهﷺ : «إِنَّهُ مَنْ لَا يَرْحَمْ لَا يُرْحَمْ».', 'ئه‌بوو هوره‌یره‌ -خودێ ژێ رازى بت- دبێژت: ئه‌قره‌عێ كوڕێ حابسى دیت پێغه‌مبه‌ر -سلاڤ لێ بن- یێ حه‌سه‌نى ماچى دكه‌ت، گۆت: من ده‌هـ زارۆك هه‌نه‌ هێشتا من ئێك ژ وان ماچى نه‌كرییه‌، پێغه‌مبه‌رى -سلاڤ لێ بن- گۆت: ئه‌وێ ب ره‌حم نه‌بت ره‌حم پێ نائێته‌برن.', NULL, true),
  (1736, 'كەس بلا مەدحێن خۆ نەكەت', 'عَنْ أَبِي هُرَيْرَةَ رضي الله عنه أَنَّ زَيْنَبَ، كَانَ اسْمُهَا بَرَّةَ فَقِيلَ: تُزَكِّي نَفْسَهَا، فَسَمَّاهَا رَسُولُ اللهﷺ زَيْنَبَ.', 'ئه‌بوو هوره‌یره‌ -خودێ ژێ رازى بت- دبێژت: ناڤێ زه‌ینه‌بێ به‌رره‌ بوو (ئانكو: قه‌نجێ) هنده‌كان گۆت: ئه‌و مه‌دحێن خۆ ب قه‌نجییێ دكه‌ت، ئینا پێغه‌مبه‌رى -سلاڤ لێ بن- ناڤێ وێ كره‌ زه‌ینه‌ب.', NULL, true);